node - <<'NODE'
const fs = require('fs');
const doc = fs.readFileSync('docs/launch/risk-control-reality-matrix.md', 'utf8');
const matrix = doc.split('\n').filter((line) => line.startsWith('| RISK-'));
const referrals = doc.split('\n').filter((line) => line.startsWith('| L2REF-L0-W04-'));
const blankJudgments = matrix.filter((line) => {
  const cells = line.split('|').map((v) => v.trim());
  return !cells[3];
});
const risks = matrix.map((line) => line.split('|')[1].trim()).sort();
const referredRisks = referrals.map((line) => line.split('|')[2].trim()).sort();
const same = JSON.stringify(risks) === JSON.stringify(referredRisks);
console.log(JSON.stringify({ matrix_rows: matrix.length, referral_rows: referrals.length, blank_judgments: blankJudgments.length, referrals_match_matrix: same, risks, referredRisks }, null, 2));
if (matrix.length !== 7 || referrals.length !== 7 || blankJudgments.length !== 0 || !same) process.exit(1);
NODE
